// Supabase Client Configuration - src/lib/supabase.ts

// Main exports:
export { supabase } from '@/lib/supabase';  // Platform-aware client
export { config, validateConfig } from '@/lib/supabase';

// Type exports:
export type {
  SupabaseClient,
  Session,
  User,
  AuthError,
  AuthChangeEvent,
  RealtimeChannel,
  RealtimePostgresChangesPayload,
} from '@/lib/supabase';

// Configuration (from constants.ts):
interface AppConfig {
  supabaseUrl: string;
  supabaseAnonKey: string;
}

// Platform-specific clients:
// - supabase.native.ts: Uses SecureStore (iOS Keychain, Android EncryptedSharedPreferences)
// - supabase.web.ts: Uses localStorage

// Auth configuration:
// - flowType: 'pkce' (secure for public clients)
// - autoRefreshToken: true
// - persistSession: true
// - detectSessionInUrl: true (web only, for OAuth callbacks)

// Environment variables (see .env.example):
// - SUPABASE_URL: Your Supabase project URL
// - SUPABASE_ANON_KEY: Your Supabase anon/public key
